def repetition_experiment(model, small_lm_head, encoded_prompt, k, ...):
    // Get the model's original prediction and top-k candidate tokens.
    with torch.no_grad():
        orig_embed = model._forward(encoded_prompt).detach()
        generated = model.lm_head(orig_embed).detach()
    generated = torch.softmax(generated, dim=-1)
    top_k = torch.topk(generated, k, dim=-1).indices[0, -1, :]

    repetition_embeds = []
    for t in torch.unbind(top_k):
        // Create a new prompt by appending a candidate token.
        prompt_with_candidate = torch.cat([encoded_prompt, t[None, None]], dim=-1)

        // Prepend the generated sequence to the original prompt to form the final test prompt.
        repetition_prompt = torch.cat(
                [
                    prompt_with_candidate,
                    torch.tensor(tokenizer.eos_id, device=DEVICE)[None, None],
                    encoded_prompt,
                ],
                dim=-1
            )

        // Get the model's embedding for the final test prompt.
        with torch.no_grad():
            repetition_embed = model._forward(repetition_prompt)[:, -1, :].detach().cpu()
            repetition_embeds.append(repetition_embed)

    return orig_embed, torch.concatenate(repetition_embeds)[None, :]

